#!/usr/bin/env python3
"""
Bug #2607: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'resize_cubic_halfpixel'], ['normalization', 'instancenorm_relu'], ['layout', 'resize_linear_halfpixel'], ['fusion', 'conv_bn_relu'], ['normalization', 'reduce_max_last'], ['broadcast', 'abs_unary_simple']]
Dependencies: numpy jax
Run         : python unique_2607.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w1 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w5 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 64, 5, 5])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w12 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(x, _w1)
    n100_inr_in = (lambda _x, _s, _b: (lambda _m, _v: jnp.reshape(_s, [1,-1]+[1]*(_x.ndim-2)) * ((_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06))) + jnp.reshape(_b, [1,-1]+[1]*(_x.ndim-2)))(jnp.mean(_x, axis=tuple(range(2,_x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(2,_x.ndim)), keepdims=True))**2, axis=tuple(range(2,_x.ndim)), keepdims=True)))(n0_resi_out, _w2, _w3)
    n100_inr_out = jnp.maximum(n100_inr_in, np.float32(0.0))
    n200_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(n100_inr_out, _w5)
    n300_cbrelu_cv = (lax.conv_general_dilated(n200_resi_out, _w6, window_strides=[2, 2], padding=((2, 2), (2, 2)), lhs_dilation=(1,1), rhs_dilation=[1, 1], dimension_numbers=('NCHW','OIHW','NCHW'), feature_group_count=1) + jnp.reshape(_w7, [1,-1,1,1]))
    n300_cbrelu_bn = (lambda _x, _s, _b, _m, _v: jnp.reshape(_s, [1,-1]+[1]*(_x.ndim-2)) * ((_x - jnp.reshape(_m, [1,-1]+[1]*(_x.ndim-2))) / jnp.sqrt(jnp.reshape(_v, [1,-1]+[1]*(_x.ndim-2)) + np.float32(9.999999747378752e-06))) + jnp.reshape(_b, [1,-1]+[1]*(_x.ndim-2)))(n300_cbrelu_cv, _w8, _w9, _w10, _w11)
    n300_cbrelu_out = jnp.maximum(n300_cbrelu_bn, np.float32(0.0))
    n400_redu_red = jnp.max(n300_cbrelu_out, axis=(-1,), keepdims=True)
    n400_redu_z = n300_cbrelu_out * _w12
    n400_redu_out = n400_redu_z + n400_redu_red
    n500_abs__a = jnp.abs(n400_redu_out)
    n500_abs__out = n500_abs__a * n400_redu_out
    return jnp.asarray(n500_abs__out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
